38	func buildService(name string) *corev1.Service {
39		return &corev1.Service{
40			ObjectMeta: metav1.ObjectMeta{
41				Name:      name,
42				Namespace: utils.Namespace(),
43				Labels: map[string]string{
44					utils.OperandLabelKey:   operandName,
45					utils.ControllerNameKey: name,
46				},
47				Annotations: map[string]string{
48					"service.beta.openshift.io/serving-cert-secret-name": name,
49				},
50			},
51			Spec: corev1.ServiceSpec{
52				Ports: []corev1.ServicePort{
53					{
54						Name:       "https",
55						Port:       443,
56						TargetPort: intstr.FromInt32(9443),
57						Protocol:   corev1.ProtocolTCP,
58					},
59					{
60						Name:       "metrics",
61						Port:       8443,
62						TargetPort: intstr.FromInt32(8443),
63						Protocol:   corev1.ProtocolTCP,
64					},
65				},
66				Selector: map[string]string{
67					utils.OperandLabelKey:   operandName,
68					utils.ControllerNameKey: name,
69				},
70			},
