74	func buildDeployment(logVerbosity int,
75		name string, replicas int32, serviceAccount string, finalizer string, args ...string) *appsv1.Deployment {
76		finalizers := make([]string, 0)
77		if finalizer != "" {
78			finalizers = append(finalizers, finalizer)
79		}
80		return &appsv1.Deployment{
81			ObjectMeta: metav1.ObjectMeta{
82				Name:      name,
83				Namespace: utils.Namespace(),
84				Labels: map[string]string{
85					utils.OperandLabelKey:   operandName,
86					utils.ControllerNameKey: name,
87				},
88				Finalizers: finalizers,
89			},
90			Spec: appsv1.DeploymentSpec{
91				Replicas: utils.NewPtr(replicas),
92				Selector: &metav1.LabelSelector{
93					MatchLabels: map[string]string{
94						utils.OperandLabelKey:   operandName,
95						utils.ControllerNameKey: name,
96					},
97				},
98				Strategy: appsv1.DeploymentStrategy{
99					Type: appsv1.RollingUpdateDeploymentStrategyType,
100					RollingUpdate: &appsv1.RollingUpdateDeployment{
101						MaxSurge:       utils.NewPtr(intstr.FromString("25%")),
102						MaxUnavailable: utils.NewPtr(intstr.FromString("25%")),
103					},
104				},
105				Template: corev1.PodTemplateSpec{
106					ObjectMeta: metav1.ObjectMeta{
107						Labels: map[string]string{
108							utils.OperandLabelKey:   operandName,
109							utils.ControllerNameKey: name,
110						},
111						Annotations: map[string]string{
112							// See https://github.com/openshift/enhancements/blob/c5b9aea25e/enhancements/workload-partitioning/management-workload-partitioning.md
113							"target.workload.openshift.io/management": "{\"effect\": \"PreferredDuringScheduling\"}",
114							requiredSCCAnnotation:                     requiredSCCRestrictedV2,
115						},
116					},
117					Spec: corev1.PodSpec{
118						AutomountServiceAccountToken: utils.NewPtr(true),
119						Affinity: &corev1.Affinity{
120							NodeAffinity: &corev1.NodeAffinity{
121								RequiredDuringSchedulingIgnoredDuringExecution: &corev1.NodeSelector{
122									NodeSelectorTerms: []corev1.NodeSelectorTerm{
123										{
124											MatchExpressions: []corev1.NodeSelectorRequirement{
125												{
126													Key:      utils.ArchLabel,
127													Operator: corev1.NodeSelectorOpIn,
128													Values: []string{
129														utils.ArchitectureAmd64,
130														utils.ArchitectureArm64,
131														utils.ArchitectureS390x,
132														utils.ArchitecturePpc64le,
133													},
134												},
135											},
136										},
137									},
138								},
139							},
140						},
141						Containers: []corev1.Container{
142							{
143								Name:            name,
144								Image:           utils.Image(),
145								ImagePullPolicy: corev1.PullIfNotPresent,
146								Env: []corev1.EnvVar{
147									{
148										Name:  "NAMESPACE",
149										Value: utils.Namespace(),
150									},
151									{
152										Name:  "HTTP_PROXY",
153										Value: os.Getenv("HTTP_PROXY"),
154									},
155									{
156										Name:  "HTTPS_PROXY",
157										Value: os.Getenv("HTTPS_PROXY"),
158									},
159	
160									{
161										Name:  "NO_PROXY",
162										Value: os.Getenv("NO_PROXY"),
163									},
164								},
165								Args: append([]string{
166									"--health-probe-bind-address=:8081",
167									"--metrics-bind-address=:8443",
168									fmt.Sprintf("--initial-log-level=%d",
169										logVerbosity),
170								}, args...),
171								Command: []string{
172									"/manager",
173								},
174								LivenessProbe: &corev1.Probe{
175									ProbeHandler: corev1.ProbeHandler{
176										HTTPGet: &corev1.HTTPGetAction{
177											Path:   "/healthz",
178											Port:   intstr.FromInt32(8081),
179											Scheme: corev1.URISchemeHTTP,
180										},
181									},
182									InitialDelaySeconds: 15,
183									TimeoutSeconds:      1,
184									PeriodSeconds:       20,
185									SuccessThreshold:    1,
186									FailureThreshold:    3,
187								},
188								ReadinessProbe: &corev1.Probe{
189									ProbeHandler: corev1.ProbeHandler{
190										HTTPGet: &corev1.HTTPGetAction{
191											Path:   "/readyz",
192											Port:   intstr.FromInt32(8081),
193											Scheme: corev1.URISchemeHTTP,
194										},
195									},
196									InitialDelaySeconds: 5,
197									TimeoutSeconds:      1,
198									PeriodSeconds:       10,
199									SuccessThreshold:    1,
200									FailureThreshold:    3,
201								},
202								Resources: corev1.ResourceRequirements{
203									Requests: corev1.ResourceList{
204										corev1.ResourceCPU:    resource.MustParse("10m"),
205										corev1.ResourceMemory: resource.MustParse("64Mi"),
206									},
207								},
208								SecurityContext: &corev1.SecurityContext{
209									AllowPrivilegeEscalation: utils.NewPtr(false),
210									Capabilities: &corev1.Capabilities{
211										Drop: []corev1.Capability{
212											"ALL",
213										},
214									},
215									Privileged:             utils.NewPtr(false),
216									ReadOnlyRootFilesystem: utils.NewPtr(true),
217									RunAsNonRoot:           utils.NewPtr(true),
218								},
219								// Generic volume mounts that all deployments need
220								VolumeMounts: []corev1.VolumeMount{
221									{
222										Name:      "trusted-ca",
223										MountPath: "/etc/pki/ca-trust/extracted/pem",
224										ReadOnly:  true,
225									},
226								},
227							},
228						},
229						PriorityClassName:  priorityClassName,
230						ServiceAccountName: serviceAccount,
231						SecurityContext: &corev1.PodSecurityContext{
232							RunAsNonRoot: utils.NewPtr(true),
233						},
234						TopologySpreadConstraints: []corev1.TopologySpreadConstraint{
235							{
236								MaxSkew:           1,
237								TopologyKey:       "kubernetes.io/hostname",
238								WhenUnsatisfiable: corev1.ScheduleAnyway,
239								LabelSelector: &metav1.LabelSelector{
240									MatchLabels: map[string]string{
241										utils.OperandLabelKey:   operandName,
242										utils.ControllerNameKey: name,
243									},
244								},
245								MatchLabelKeys: []string{"pod-template-hash"},
246							},
247						},
248						// Generic volumes that all deployments need
249						Volumes: []corev1.Volume{
250							{
251								Name: "trusted-ca",
252								VolumeSource: corev1.VolumeSource{
253									ConfigMap: &corev1.ConfigMapVolumeSource{
254										LocalObjectReference: corev1.LocalObjectReference{
255											Name: "multiarch-tuning-operator-trusted-ca",
256										},
257										Items: []corev1.KeyToPath{
258											{
259												Key:  "ca-bundle.crt",
260												Path: "tls-ca-bundle.pem",
261											},
262										},
263									},
264								},
265							},
266						},
267					},
268				},
269			},
270		}
271	}
