227	// buildEnoexecDeployment returns a minimal Deployment object matching your YAML
228	func buildDeploymentENoExecEventHandler(logVerbosity int) *appsv1.Deployment {
229		d := buildDeployment(logVerbosity, utils.EnoexecControllerName, 2, utils.EnoexecControllerName, "",
230			"--leader-elect", "--enable-enoexec-event-controllers",
231		)
232		additionalVolumes := []corev1.Volume{
233			{
234				Name: "metrics-cert",
235				VolumeSource: corev1.VolumeSource{
236					Secret: &corev1.SecretVolumeSource{
237						SecretName:  utils.EnoexecControllerName,
238						DefaultMode: utils.NewPtr(int32(420)),
239					},
240				},
241			},
242		}
243		additionalMounts := []corev1.VolumeMount{
244			{
245				Name:      "metrics-cert",
246				MountPath: "/var/run/manager/tls",
247				ReadOnly:  true,
248			},
249		}
250	
251		d.Spec.Template.Spec.Volumes = append(d.Spec.Template.Spec.Volumes, additionalVolumes...)
252		d.Spec.Template.Spec.Containers[0].VolumeMounts = append(d.Spec.Template.Spec.Containers[0].VolumeMounts, additionalMounts...)
253	
254		return d
255	}
